{{日本の寺院 |名称 = {{ill|Koyama-ji|ja|甲山寺|qq=draft|12=simple|13=User:Immanuelle/Koyama-ji|qq=}} |image = Kōyama-ji, Main Hall 001.jpg |imageサイズ = 250 |image説明 = Main Hall |所在地 = [[:en:Kagawa Prefecture|Kagawa Prefecture]][[:en:Zentsūji, Kagawa|Zentsūji City]] 弘田町1765-1 |位置 = {{Coord|34|13|59.5|N|133|45|56.75|E|type:landmark_region:JP-37|display=inline,title}} |山号 = [[:en:Iozen|Iōzan]] |院号 = {{ill|Taho-in|ja|多宝院|qq=draft|12=simple|13=User:Immanuelle/Taho-in|qq=}} |宗旨 = |宗派 = {{ill|Shingon Shentsū-ji Sect|ja|真言宗善通寺派|qq=draft|12=simple|13=User:Immanuelle/Shingon Shentsū-ji Sect|qq=}} |寺格 = |本尊 = [[:en:Bhaisajyaguru|Yakushi Nyorai Medicine Buddha]] |創建年 = (伝) [[:en:Kōnin (era)|Kōnin]]12nd year ([[:en:821|821]]) |開山 = |開基 = (伝) [[:en:Kūkai|Kūkai]] ({{ill|Kōbō Daishi|ja|弘法大師|qq=draft|12=simple|13=User:Immanuelle/Kōbō Daishi|qq=}}) |中興年 = |中興 = |正式名 = {{ill|Iōzan Taho-in Koyama-ji|ja|医王山 多宝院 甲山寺|qq=draft|12=simple|13=User:Immanuelle/Iōzan Taho-in Koyama-ji|qq=}} |別称 = |札所等 = [[:en:Shikoku Pilgrimage|Shikoku 88 Temples]] No.74 |文化財 = |公式HP = https://koyamaji.or.jp/ |公式HP名 = [Kagawa] Iōzan Taho-in Koyama-ji |地図2 = {{Switcher | {{Location map+|Japan Kagawa|width=230|caption= |float=center|places= {{Location map~|Japan Kagawa|lat_deg=34|lat_min=13|lat_sec=59.5|lon_deg=133|lon_min=45|lon_sec=56.75|mark=Indian_Swastika.svg|marksize=12|position=left|label={{ill|Koyama-ji|ja|甲山寺|qq=draft|12=simple|13=User:Immanuelle/Koyama-ji|qq=}}|label_size=100|caption=}} {{Location map~|Japan Kagawa|lat_deg=34|lat_min=21|lat_sec=2.46|lon_deg=134|lon_min=2|lon_sec=48.98|mark=blue pog.svg|position=top|label=[[:en:Takamatsu Station|Takamatsu Station (Kagawa)]]|label_size=95}} {{Location map~|Japan Kagawa|lat_deg=34|lat_min=12|lat_sec=51|lon_deg=134|lon_min=0|lon_sec=56|mark=BSicon FLUGg.svg|marksize=10|position=bottom|label=[[:en:Takamatsu Airport|Takamatsu Airport]]|label_size=95}}}} | Position in Kagawa Prefecture | {{maplink2|frame=yes|plain=yes|type=point|zoom=14|frame-align=center|frame-width=230}